import React from 'react';
import { useDrop } from 'react-dnd';
import DraggablePlayer from './DraggablePlayer';
import './TeamDisplay.css';

const TeamDisplay = ({ teams, showDetails, calculateAverageRating, movePlayer }) => {
  return (
    <div className="teams-container">
      {teams.map((team, index) => {
        // Create a drop zone for each team
        const [, dropRef] = useDrop({
          accept: 'PLAYER',
          drop: (draggedItem) => {
            movePlayer(draggedItem, index); // Pass the dragged player and target team index
          },
        });

        return (
          <div key={index} ref={dropRef} className="team-card">
            <h4>
              Team {index + 1}: {team.length} players
            </h4>
            <h4>
              Average Rating: {calculateAverageRating(team).toFixed(2)}
            </h4>
            <table className="table table-striped table-bordered">
              <thead>
                <tr>
                  {showDetails && <th>Rating</th>}
                </tr>
              </thead>
              <tbody>
                {team.map((player, playerIndex) => (
                  <DraggablePlayer
                    key={player.id}
                    player={player}
                    teamIndex={index}
                    playerIndex={playerIndex}
                    movePlayer={movePlayer}
                    showDetails={showDetails}
                  />
                ))}
              </tbody>
            </table>
          </div>
        );
      })}
    </div>
  );
};

export default TeamDisplay;
